const base = env.get('MDP_BASE_URL') || 'http://reverse-proxy:8456';
const key = env.get('MDP_INBOUND_KEY') || '';
const machines = ['M-01', 'M-02', 'M-03'];
const m = machines[Math.floor(Math.random() * machines.length)];
const now = Date.now();
msg.method = 'POST';
msg.url = base + '/api/inbound/sim_reading';
msg.headers = { 'Content-Type': 'application/json', 'X-API-Key': key };
msg.payload = {
    reading_id: 'R-' + now + '-' + Math.floor(Math.random() * 1000),
    machine: m,
    metric: 'temperature',
    value: Math.round((50 + Math.random() * 50) * 10) / 10
};
return msg;
